Health'i ayrı component yapmak Player, enemy ve kırılabilir objelerde yeniden kullanımı kolaylaştırır.

```csharp
using System;
using UnityEngine;

public class Health : MonoBehaviour
{
    [SerializeField] private int maxHealth = 100;

    public int Current { get; private set; }
    public event Action<int, int> Changed;
    public event Action Died;

    private void Awake()
    {
        Current = maxHealth;
    }

    public void TakeDamage(int amount)
    {
        Current = Mathf.Max(Current - amount, 0);
        Changed?.Invoke(Current, maxHealth);

        if (Current == 0)
            Died?.Invoke();
    }
}
```

Reusable health için `UActorComponent` uygundur.

```cpp
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UHealthComponent : public UActorComponent
{
    GENERATED_BODY()

public:
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category="Health")
    float MaxHealth = 100.0f;

    UPROPERTY(BlueprintReadOnly, Category="Health")
    float CurrentHealth = 100.0f;

    UFUNCTION(BlueprintCallable, Category="Health")
    void ApplyDamage(float Amount)
    {
        CurrentHealth = FMath::Clamp(CurrentHealth - Amount, 0.0f, MaxHealth);
        if (CurrentHealth <= 0.0f)
        {
            // Death event veya BlueprintImplementableEvent çağrılabilir.
        }
    }
};
```

Daha gelişmiş sürümde multicast delegate ile UI ve gameplay sistemlerine haber verilir.

FPS karakterinde instant hit ateş için `UCameraComponent` üzerinden başlayıp ileri yöne line trace atabilirsin. Muzzle'dan debug line çizmek sonucu görmeyi kolaylaştırır.

```cpp
#include "DrawDebugHelpers.h"
#include "Camera/CameraComponent.h"
#include "Kismet/GameplayStatics.h"

void AMyProjectCharacter::OnFire()
{
    FVector StartLocation = FirstPersonCameraComponent->GetComponentLocation();
    FVector AimDirection = FirstPersonCameraComponent->GetForwardVector();
    FVector EndLocation = StartLocation + AimDirection * 20000.0f;

    FHitResult Hit;
    bool bHit = GetWorld()->LineTraceSingleByChannel(
        Hit,
        StartLocation,
        EndLocation,
        ECC_Visibility
    );

    FVector TraceEnd = bHit ? Hit.Location : EndLocation;
    DrawDebugLine(
        GetWorld(),
        FP_MuzzleLocation->GetComponentLocation(),
        TraceEnd,
        FColor::Green,
        false,
        2.0f
    );

    if (bHit)
    {
        DrawDebugString(GetWorld(), Hit.ImpactPoint, TEXT("Hit"), nullptr, FColor::White, 2.0f);
    }

    if (FireSound)
    {
        UGameplayStatics::PlaySoundAtLocation(this, FireSound, GetActorLocation());
    }
}
```

