TArray<FHitResult> Hits;
FVector Start = GetActorLocation();
FVector End = Start + GetActorForwardVector() * 500.0f;
FCollisionShape Sphere = FCollisionShape::MakeSphere(75.0f);

bool bHit = GetWorld()->SweepMultiByChannel(
    Hits,
    Start,
    End,
    FQuat::Identity,
    ECC_Pawn,
