Sweep, bir şekli iki nokta arasında hareket ettirip çarpışan aktörleri bulur. AoE, melee hitbox veya projectile yakın kontrolü için kullanılabilir.

```cpp
TArray<FHitResult> Hits;
FVector Start = GetActorLocation();
FVector End = Start + GetActorForwardVector() * 500.0f;
FCollisionShape Sphere = FCollisionShape::MakeSphere(75.0f);

bool bHit = GetWorld()->SweepMultiByChannel(
    Hits,
    Start,
    End,
    FQuat::Identity,
    ECC_Pawn,
    Sphere
);

if (bHit)
{
    for (const FHitResult& Hit : Hits)
    {
        AActor* HitActor = Hit.GetActor();
        if (HitActor)
        {
            UE_LOG(LogTemp, Log, TEXT("Sweep hit: %s"), *HitActor->GetName());
        }
    }
}
```

