FPS karakterinde instant-hit ates icin kameradan ileri yone line trace atabilirsin.

```cpp
#include "Camera/CameraComponent.h"
#include "DrawDebugHelpers.h"

void AMyProjectCharacter::FireLineTrace()
{
    if (!FirstPersonCameraComponent)
    {
        return;
    }

    const FVector Start = FirstPersonCameraComponent->GetComponentLocation();
    const FVector End = Start + FirstPersonCameraComponent->GetForwardVector() * 20000.0f;

    FHitResult Hit;
    FCollisionQueryParams Params;
    Params.AddIgnoredActor(this);

    const bool bHit = GetWorld()->LineTraceSingleByChannel(
        Hit,
        Start,
        End,
        ECC_Visibility,
        Params
    );

    const FVector TraceEnd = bHit ? Hit.ImpactPoint : End;
    DrawDebugLine(GetWorld(), Start, TraceEnd, FColor::Green, false, 2.0f, 0, 1.5f);

    if (bHit && Hit.GetActor())
    {
        UE_LOG(LogTemp, Log, TEXT("Hit: %s"), *Hit.GetActor()->GetName());
    }
}
```

Header tarafinda kamera icin `UPROPERTY(VisibleAnywhere) UCameraComponent* FirstPersonCameraComponent;` tutmak yaygindir.

FPS karakterinde instant hit ateş için `UCameraComponent` üzerinden başlayıp ileri yöne line trace atabilirsin. Muzzle'dan debug line çizmek sonucu görmeyi kolaylaştırır.

```cpp
#include "DrawDebugHelpers.h"
#include "Camera/CameraComponent.h"
#include "Kismet/GameplayStatics.h"

void AMyProjectCharacter::OnFire()
{
    FVector StartLocation = FirstPersonCameraComponent->GetComponentLocation();
    FVector AimDirection = FirstPersonCameraComponent->GetForwardVector();
    FVector EndLocation = StartLocation + AimDirection * 20000.0f;

    FHitResult Hit;
    bool bHit = GetWorld()->LineTraceSingleByChannel(
        Hit,
        StartLocation,
        EndLocation,
        ECC_Visibility
    );

    FVector TraceEnd = bHit ? Hit.Location : EndLocation;
    DrawDebugLine(
        GetWorld(),
        FP_MuzzleLocation->GetComponentLocation(),
        TraceEnd,
        FColor::Green,
        false,
        2.0f
    );

    if (bHit)
    {
        DrawDebugString(GetWorld(), Hit.ImpactPoint, TEXT("Hit"), nullptr, FColor::White, 2.0f);
    }

    if (FireSound)
    {
        UGameplayStatics::PlaySoundAtLocation(this, FireSound, GetActorLocation());
    }
}
```

