FPS karakterinde instant hit ateş için `UCameraComponent` üzerinden başlayıp ileri yöne line trace atabilirsin. Muzzle'dan debug line çizmek sonucu görmeyi kolaylaştırır.

```cpp
#include "DrawDebugHelpers.h"
#include "Camera/CameraComponent.h"
#include "Kismet/GameplayStatics.h"

void AMyProjectCharacter::OnFire()
{
    FVector StartLocation = FirstPersonCameraComponent->GetComponentLocation();
    FVector AimDirection = FirstPersonCameraComponent->GetForwardVector();
    FVector EndLocation = StartLocation + AimDirection * 20000.0f;

    FHitResult Hit;
    bool bHit = GetWorld()->LineTraceSingleByChannel(
        Hit,
        StartLocation,
        EndLocation,
        ECC_Visibility
    );

    FVector TraceEnd = bHit ? Hit.Location : EndLocation;
    DrawDebugLine(
        GetWorld(),
        FP_MuzzleLocation->GetComponentLocation(),
        TraceEnd,
        FColor::Green,
        false,
        2.0f
    );

    if (bHit)
    {
        DrawDebugString(GetWorld(), Hit.ImpactPoint, TEXT("Hit"), nullptr, FColor::White, 2.0f);
    }

    if (FireSound)
    {
        UGameplayStatics::PlaySoundAtLocation(this, FireSound, GetActorLocation());
    }
}
```

